import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Alert,
  CircularProgress,
  Paper,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupUser } from "../services/api";

export default function UserRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setFormData((p) => ({ ...p, [e.target.name]: e.target.value }));

  const validateEmail = (email) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateForm = () => {
    if (!formData.fullName.trim()) return setError("Please enter your full name.");
    if (!validateEmail(formData.email)) return setError("Enter a valid email address.");
    if (!/^[6-9]\d{9}$/.test(formData.mobile)) return setError("Enter a valid mobile number.");
    setError(""); return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;
    setLoading(true);
    try {
      const res = await signupUser({ ...formData, role: "user" });
      if (res.data?.success) {
        setSuccess("Signup successful! Redirecting...");
        setTimeout(() => navigate("/login"), 1500);
      } else setError("Signup failed.");
    } catch {
      setError("Server error.");
    } finally { setLoading(false); }
  };

  return (
    <Container maxWidth="sm" sx={{ display: "flex", alignItems: "center", height: "100vh" }}>
      <Paper sx={{ p: 5, borderRadius: 4, boxShadow: 5, width: "100%", textAlign: "center" }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 1, color: "primary.main" }}>
          User Signup
        </Typography>
        <Typography variant="body2" sx={{ mb: 3, color: "text.secondary" }}>
          Create your account to get started
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField fullWidth label="Full Name" name="fullName" value={formData.fullName} onChange={handleChange} margin="normal" />
          <TextField fullWidth type="email" label="Email" name="email" value={formData.email} onChange={handleChange} margin="normal" />
          <TextField fullWidth label="Mobile Number" name="mobile" value={formData.mobile} onChange={handleChange} margin="normal" />

          <Button fullWidth type="submit" sx={{ mt: 3, py: 1.3 }} variant="contained" disabled={loading}>
            {loading ? <CircularProgress size={24} /> : "Sign Up"}
          </Button>
        </Box>

        <Typography sx={{ mt: 3 }}>
          Already have an account?{" "}
          <Button onClick={() => navigate("/login")} sx={{ fontWeight: "bold" }}>Login</Button>
        </Typography>
        <Typography sx={{ mt: 1 }}>
          Want to drive with us?{" "}
          <Button onClick={() => navigate("/rider-register")} sx={{ fontWeight: "bold" }}>Rider Signup</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
